example.code:
# .github/workflows/cd.yml name: CD on: push: branches: [main] workflow_dispatch: inputs: environment: description: 'Target environment' required: true default: 'staging' type: choice options: [staging, production]
concurrency: group: deploy-${{ github.ref }} cancel-in-progress: false # never cancel in-flight deploys
jobs: build: name: Build Docker Image runs-on: ubuntu-latest timeout-minutes: 60 outputs: image-tag: ${{ steps.meta.outputs.tags }} steps: - uses: actions/checkout@v4 - uses: docker/setup-buildx-action@v3 - uses: docker/login-action@v3 with: registry: ghcr.io username: ${{ github.actor }} password: ${{ secrets.GITHUB_TOKEN }} - id: meta uses: docker/metadata-action@v5 with: images: ghcr.io/${{ github.repository }} tags: | type=sha,prefix= type=raw,value=latest,enable={{is_default_branch}} - uses: docker/build-push-action@v6 with: context: . platforms: linux/amd64,linux/arm64 push: true tags: ${{ steps.meta.outputs.tags }} cache-from: type=gha cache-to: type=gha,mode=max
staging: name: Deploy to Staging runs-on: ubuntu-latest needs: build timeout-minutes: 30 environment: name: staging url: https://staging.example.com steps: - uses: actions/checkout@v4 - uses: aws-actions/configure-aws-credentials@v4 with: role-to-assume: ${{ secrets.AWS_ROLE_ARN }} aws-region: eu-central-1 - uses: azure/setup-kubectl@v4 with: { version: 'v1.29.0' } - run: aws eks update-kubeconfig --name staging-cluster --region eu-central-1 - run: | kubectl set image deployment/app \ app=ghcr.io/${{ github.repository }}:${{ github.sha }} \ -n staging kubectl rollout status deployment/app -n staging --timeout=5m - name: Run smoke tests run: npm ci && npm run test:smoke -- --url=https://staging.example.com - if: failure() uses: slackapi/slack-github-action@v1.26.0 with: payload: '{"text": ":x: Staging deploy failed: ${{ github.repository }}"}' env: SLACK_WEBHOOK_URL: ${{ secrets.SLACK_WEBHOOK }}
production: name: Deploy to Production runs-on: ubuntu-latest needs: staging timeout-minutes: 120 if: github.ref == 'refs/heads/main' environment: name: production url: https://example.com steps: - uses: actions/checkout@v4 - uses: aws-actions/configure-aws-credentials@v4 with: role-to-assume: ${{ secrets.AWS_PROD_ROLE_ARN }} aws-region: eu-central-1 - uses: azure/setup-kubectl@v4 with: { version: 'v1.29.0' } - run: aws eks update-kubeconfig --name production-cluster --region eu-central-1 - name: Deploy canary (10% traffic) run: | kubectl set image deployment/app-canary \ app=ghcr.io/${{ github.repository }}:${{ github.sha }} \ -n production kubectl rollout status deployment/app-canary -n production --timeout=5m sleep 300 kubectl set image deployment/app \ app=ghcr.io/${{ github.repository }}:${{ github.sha }} \ -n production kubectl rollout status deployment/app -n production --timeout=10m - uses: getsentry/action-release@v1 env: SENTRY_AUTH_TOKEN: ${{ secrets.SENTRY_AUTH_TOKEN }} SENTRY_ORG: ${{ vars.SENTRY_ORG }} SENTRY_PROJECT: ${{ vars.SENTRY_PROJECT }} with: environment: production version: ${{ github.sha }}

- uses: appleboy/ssh-action@v1.0.3
  with:
    host: ${{ secrets.SSH_HOST }}
    username: ${{ secrets.SSH_USER }}
    key: ${{ secrets.SSH_KEY }}
    port: ${{ secrets.SSH_PORT }}
    script: |
      cd /var/www/app
      git pull origin main
      npm ci
      npm run build
      pm2 restart app

- uses: amondnet/vercel-action@v25
  with:
    vercel-token: ${{ secrets.VERCEL_TOKEN }}
    vercel-org-id: ${{ secrets.VERCEL_ORG_ID }}
    vercel-project-id: ${{ secrets.VERCEL_PROJECT_ID }}
    vercel-args: '--prod'
